import { memo, useEffect, useMemo, useState, useCallback } from 'react'

import dayjs from 'dayjs'
import { useNavigate } from 'react-router-dom'

import CalendarMonthIcon from '@mui/icons-material/CalendarMonth'
import SchoolIcon from '@mui/icons-material/School'
import TrendingUpIcon from '@mui/icons-material/TrendingUp'
import {
  Alert,
  Box,
  Button,
  Card,
  CardContent,
  Chip,
  CircularProgress,
  List,
  ListItem,
  ListItemButton,
  ListItemText,
  Typography,
} from '@mui/material'

import { type LearningHistoryRow, getAllLearningHistories } from '@/api/learningHistories'
import { useAuth } from '@/contexts/AuthContext'
import { routes } from '@/routes'

function useDashboardStats(histories: LearningHistoryRow[]) {
  return useMemo(() => {
    const today = dayjs().format('YYYY-MM-DD')

    // Today's session count (fin records)
    const finRecords = histories.filter((h) => h.type === 'fin')
    const todayCount = finRecords.filter(
      (h) => dayjs(h.created_at).format('YYYY-MM-DD') === today
    ).length

    // Total session count
    const total = finRecords.length

    // Learning streak (consecutive days)
    let streak = 0
    const now = dayjs()
    for (let i = 0; i < 365; i++) {
      const dateStr = now.subtract(i, 'day').format('YYYY-MM-DD')
      const hasLearning = finRecords.some(
        (h) => dayjs(h.created_at).format('YYYY-MM-DD') === dateStr
      )
      if (hasLearning) {
        streak++
      } else if (i > 0) {
        break
      }
    }

    // Weekly stats (last 7 days)
    const weeklyStats = Array.from({ length: 7 }, (_, i) => {
      const date = now.subtract(6 - i, 'day')
      const dateStr = date.format('YYYY-MM-DD')
      const dayHistories = histories.filter(
        (h) => dayjs(h.created_at).format('YYYY-MM-DD') === dateStr && h.type !== 'fin'
      )
      const passed = dayHistories.filter((h) => h.type === 'pass').length
      const failed = dayHistories.filter((h) => h.type === 'fail').length
      return {
        date: date.format('MM/DD'),
        passed,
        failed,
        total: passed + failed,
      }
    })

    // Learning history grouped by date and path (recent 7 days)
    const dateGroups = new Map<
      string,
      Map<string, { owner: string; repo: string; path: string; count: number }>
    >()

    finRecords.forEach((h) => {
      const dateStr = dayjs(h.created_at).format('YYYY-MM-DD')
      if (!dateGroups.has(dateStr)) {
        dateGroups.set(dateStr, new Map())
      }
      const pathKey = `${h.owner}/${h.repo}/${h.path}`
      const pathGroups = dateGroups.get(dateStr)!
      const existing = pathGroups.get(pathKey) || {
        owner: h.owner,
        repo: h.repo,
        path: h.path,
        count: 0,
      }
      existing.count++
      pathGroups.set(pathKey, existing)
    })

    const flashCardsByDate = Array.from(dateGroups.entries())
      .sort(([a], [b]) => b.localeCompare(a))
      .slice(0, 7)
      .map(([dateStr, pathGroups]) => {
        const pathGroupsArray = Array.from(pathGroups.values())
        const totalCount = pathGroupsArray.reduce((sum, pg) => sum + pg.count, 0)
        return {
          date: dateStr,
          displayDate: dayjs(dateStr).format('MM/DD (ddd)'),
          pathGroups: pathGroupsArray,
          totalCount,
        }
      })

    // Recommendations (low pass rate content, min 3 attempts, <70%)
    const contentStats = new Map<
      string,
      { owner: string; repo: string; path: string; passed: number; failed: number }
    >()

    histories
      .filter((h) => h.type !== 'fin')
      .forEach((h) => {
        const key = `${h.owner}/${h.repo}/${h.path}`
        const existing = contentStats.get(key) || {
          owner: h.owner,
          repo: h.repo,
          path: h.path,
          passed: 0,
          failed: 0,
        }
        if (h.type === 'pass') existing.passed++
        else if (h.type === 'fail') existing.failed++
        contentStats.set(key, existing)
      })

    const recommendations = Array.from(contentStats.values())
      .filter((stat) => {
        const t = stat.passed + stat.failed
        const passRate = t > 0 ? (stat.passed / t) * 100 : 0
        return t >= 3 && passRate < 70
      })
      .map((stat) => {
        const t = stat.passed + stat.failed
        return { ...stat, total: t, passRate: (stat.passed / t) * 100 }
      })
      .sort((a, b) => a.passRate - b.passRate)
      .slice(0, 5)

    return { todayCount, total, streak, weeklyStats, flashCardsByDate, recommendations }
  }, [histories])
}

// Simple bar chart using MUI Box
function WeeklyChart({
  data,
}: {
  data: { date: string; passed: number; failed: number; total: number }[]
}) {
  const maxTotal = Math.max(...data.map((d) => d.total), 1)

  return (
    <Box sx={{ display: 'flex', alignItems: 'flex-end', gap: 1, height: 160 }}>
      {data.map((d) => {
        const passH = (d.passed / maxTotal) * 140
        const failH = (d.failed / maxTotal) * 140
        return (
          <Box
            key={d.date}
            sx={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center' }}
          >
            <Box
              sx={{
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'flex-end',
                height: 140,
              }}
            >
              {d.total > 0 && (
                <>
                  <Box
                    sx={{
                      height: failH,
                      bgcolor: '#f44336',
                      borderRadius: '4px 4px 0 0',
                      minWidth: 20,
                    }}
                  />
                  <Box
                    sx={{
                      height: passH,
                      bgcolor: '#4caf50',
                      borderRadius: failH > 0 ? 0 : '4px 4px 0 0',
                      minWidth: 20,
                    }}
                  />
                </>
              )}
            </Box>
            <Typography
              variant="caption"
              color="text.secondary"
              sx={{ mt: 0.5, fontSize: '0.65rem' }}
            >
              {d.date}
            </Typography>
          </Box>
        )
      })}
    </Box>
  )
}

function FlashManStatsPageContent() {
  const navigate = useNavigate()
  const { user } = useAuth()
  const [histories, setHistories] = useState<LearningHistoryRow[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  const loadData = useCallback(async () => {
    try {
      setLoading(true)
      const data = await getAllLearningHistories(user?.id)
      setHistories(data)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load data')
    } finally {
      setLoading(false)
    }
  }, [user?.id])

  useEffect(() => {
    if (user) {
      loadData()
    }
  }, [user, loadData])

  const stats = useDashboardStats(histories)

  if (loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', py: 8 }}>
        <CircularProgress />
      </Box>
    )
  }

  if (error) {
    return (
      <Box sx={{ p: 2 }}>
        <Alert severity="error">{error}</Alert>
      </Box>
    )
  }

  return (
    <Box sx={{ p: 2, display: 'flex', flexDirection: 'column', gap: 2 }}>
      {/* Stats Cards */}
      <Box
        sx={{
          display: 'grid',
          gridTemplateColumns: 'repeat(3, 1fr)',
          gap: 1,
        }}
      >
        <Card>
          <CardContent sx={{ p: 1.5, '&:last-child': { pb: 1.5 } }}>
            <Box sx={{ display: 'flex', alignItems: 'center', mb: 0.5 }}>
              <SchoolIcon color="primary" fontSize="small" sx={{ mr: 0.5 }} />
              <Typography variant="caption" color="text.secondary">
                오늘 학습
              </Typography>
            </Box>
            <Typography variant="h5" sx={{ fontWeight: 'bold' }}>
              {stats.todayCount}
            </Typography>
            <Typography variant="caption" color="text.secondary">
              세션
            </Typography>
          </CardContent>
        </Card>

        <Card>
          <CardContent sx={{ p: 1.5, '&:last-child': { pb: 1.5 } }}>
            <Box sx={{ display: 'flex', alignItems: 'center', mb: 0.5 }}>
              <TrendingUpIcon color="success" fontSize="small" sx={{ mr: 0.5 }} />
              <Typography variant="caption" color="text.secondary">
                전체 학습
              </Typography>
            </Box>
            <Typography variant="h5" sx={{ fontWeight: 'bold' }}>
              {stats.total}
            </Typography>
            <Typography variant="caption" color="text.secondary">
              세션
            </Typography>
          </CardContent>
        </Card>

        <Card>
          <CardContent sx={{ p: 1.5, '&:last-child': { pb: 1.5 } }}>
            <Box sx={{ display: 'flex', alignItems: 'center', mb: 0.5 }}>
              <CalendarMonthIcon color="info" fontSize="small" sx={{ mr: 0.5 }} />
              <Typography variant="caption" color="text.secondary">
                연속 학습
              </Typography>
            </Box>
            <Typography variant="h5" sx={{ fontWeight: 'bold' }}>
              {stats.streak}
            </Typography>
            <Typography variant="caption" color="text.secondary">
              일
            </Typography>
          </CardContent>
        </Card>
      </Box>

      {/* Learning History by Date */}
      {stats.flashCardsByDate.length > 0 && (
        <Card>
          <CardContent>
            <Typography variant="h6" sx={{ mb: 2 }}>
              학습 기록
            </Typography>
            {stats.flashCardsByDate.map((dateGroup) => (
              <Box key={dateGroup.date} sx={{ mb: 2 }}>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                  <Typography variant="subtitle2" color="text.secondary">
                    {dateGroup.displayDate}
                  </Typography>
                  <Chip
                    label={`${dateGroup.totalCount}회`}
                    size="small"
                    color="primary"
                    variant="outlined"
                  />
                </Box>
                <List sx={{ py: 0 }}>
                  {dateGroup.pathGroups.map((pg) => (
                    <ListItem key={`${pg.owner}/${pg.repo}/${pg.path}`} disablePadding>
                      <ListItemButton
                        sx={{ px: 1, py: 0.5 }}
                        onClick={() =>
                          navigate(
                            routes.flashMan.cards.$({
                              owner: pg.owner,
                              repo: pg.repo,
                              path: pg.path,
                            })
                          )
                        }
                      >
                        <ListItemText
                          disableTypography
                          primary={
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                              <Chip label={`${pg.count}회`} size="small" sx={{ flexShrink: 0 }} />
                              <Box sx={{ minWidth: 0 }}>
                                <Typography
                                  variant="body2"
                                  sx={{ fontFamily: 'monospace', wordBreak: 'break-all', lineHeight: 1.3 }}
                                >
                                  {pg.path}
                                </Typography>
                                <Typography
                                  variant="caption"
                                  color="text.secondary"
                                  sx={{ fontFamily: 'monospace' }}
                                >
                                  {pg.owner}/{pg.repo}
                                </Typography>
                              </Box>
                            </Box>
                          }
                        />
                      </ListItemButton>
                    </ListItem>
                  ))}
                </List>
              </Box>
            ))}
          </CardContent>
        </Card>
      )}

      {/* Weekly Chart */}
      {stats.weeklyStats.some((s) => s.total > 0) && (
        <Card>
          <CardContent>
            <Typography variant="h6" sx={{ mb: 2 }}>
              최근 7일 학습 통계
            </Typography>
            <WeeklyChart data={stats.weeklyStats} />
            <Box sx={{ display: 'flex', gap: 2, mt: 2, justifyContent: 'center' }}>
              <Box sx={{ display: 'flex', alignItems: 'center' }}>
                <Box sx={{ width: 12, height: 12, bgcolor: '#4caf50', borderRadius: 1, mr: 0.5 }} />
                <Typography variant="caption">성공</Typography>
              </Box>
              <Box sx={{ display: 'flex', alignItems: 'center' }}>
                <Box sx={{ width: 12, height: 12, bgcolor: '#f44336', borderRadius: 1, mr: 0.5 }} />
                <Typography variant="caption">실패</Typography>
              </Box>
            </Box>
          </CardContent>
        </Card>
      )}

      {/* Recommendations */}
      {stats.recommendations.length > 0 && (
        <Card>
          <CardContent>
            <Typography variant="h6" sx={{ mb: 2 }}>
              복습이 필요한 콘텐츠
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              통과율이 낮은 콘텐츠를 다시 학습해보세요
            </Typography>
            <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1 }}>
              {stats.recommendations.map((rec) => {
                const fileName = rec.path.split('/').pop() || rec.path
                return (
                  <Card key={`${rec.owner}/${rec.repo}/${rec.path}`} variant="outlined">
                    <CardContent sx={{ pb: 1, '&:last-child': { pb: 1 } }}>
                      <Box>
                        <Box sx={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', gap: 1 }}>
                          <Box sx={{ flex: 1, minWidth: 0 }}>
                            <Typography variant="body2" sx={{ fontWeight: 'medium', wordBreak: 'break-all' }}>
                              {fileName}
                            </Typography>
                            <Typography
                              variant="caption"
                              color="text.secondary"
                              sx={{ fontFamily: 'monospace', wordBreak: 'break-all' }}
                            >
                              {rec.owner}/{rec.repo}
                            </Typography>
                          </Box>
                          <Button
                            size="small"
                            variant="contained"
                            sx={{ flexShrink: 0 }}
                            onClick={() =>
                              navigate(
                                routes.flashMan.learn.$({
                                  owner: rec.owner,
                                  repo: rec.repo,
                                  path: rec.path,
                                })
                              )
                            }
                          >
                            학습
                          </Button>
                        </Box>
                        <Box sx={{ display: 'flex', gap: 1, mt: 1, flexWrap: 'wrap' }}>
                          <Chip
                            label={`통과율 ${Math.round(rec.passRate)}%`}
                            size="small"
                            color="error"
                            variant="outlined"
                          />
                          <Chip label={`${rec.total}회 학습`} size="small" variant="outlined" />
                        </Box>
                      </Box>
                    </CardContent>
                  </Card>
                )
              })}
            </Box>
          </CardContent>
        </Card>
      )}

      {/* Quick Navigation */}
      <Button
        variant="outlined"
        fullWidth
        onClick={() => navigate(routes.flashMan.contents.$())}
      >
        콘텐츠 탐색
      </Button>
    </Box>
  )
}

export const FlashManStatsPage = memo(FlashManStatsPageContent)
